mybatis 实现一对多的查询方式

package com.sgcc.demo.model.bo;/**   * @author liyalong * @description //TODO  * @date 13:44 2019/12/2 **/import com.sgcc.demo.model.po.DemoFileInfo;import com.sgcc.demo.model.po.DemoFileManagement;import lombok.Data;import java.util.List;@Datapublic class DemoFileManagementBo extends DemoFileManagement &#123;    // 文件list    private List&lt;DemoFileInfo&gt; fileInfos;&#125;
第一种 （适合单条查询一对多）
这种方式仅适合于 查询一条信息，或者多条信息不使用PageQuery进行分页的情况下。（效率比较快，然是局限性比较强）

&lt;resultMap id=&quot;BaseResultMap&quot; type=&quot;com.sgcc.demo.model.po.DemoFileManagement&quot;&gt;       &lt;id column=&quot;GUID&quot; jdbcType=&quot;VARCHAR&quot; property=&quot;guid&quot;/&gt;       &lt;result column=&quot;NAME&quot; jdbcType=&quot;VARCHAR&quot; property=&quot;name&quot;/&gt;       &lt;result column=&quot;VERSION&quot; jdbcType=&quot;VARCHAR&quot; property=&quot;version&quot;/&gt;       &lt;result column=&quot;REMARK&quot; jdbcType=&quot;VARCHAR&quot; property=&quot;remark&quot;/&gt;       &lt;result column=&quot;UPDATE_TIME&quot; jdbcType=&quot;TIMESTAMP&quot; property=&quot;updateTime&quot;/&gt;       &lt;result column=&quot;DELETE_FLG&quot; jdbcType=&quot;CHAR&quot; property=&quot;deleteFlg&quot;/&gt;   &lt;/resultMap&gt;   &lt;resultMap id=&quot;fileMap&quot; type=&quot;com.sgcc.demo.model.po.DemoFileInfo&quot;&gt;       &lt;id column=&quot;GUID&quot; jdbcType=&quot;VARCHAR&quot; property=&quot;guid&quot;/&gt;       &lt;result column=&quot;INFO_ID&quot; jdbcType=&quot;VARCHAR&quot; property=&quot;infoId&quot;/&gt;       &lt;result column=&quot;FILE_NAME&quot; jdbcType=&quot;VARCHAR&quot; property=&quot;fileName&quot;/&gt;       &lt;result column=&quot;FILE_ADDRESS&quot; jdbcType=&quot;VARCHAR&quot; property=&quot;fileAddress&quot;/&gt;       &lt;result column=&quot;CREATE_TIME&quot; jdbcType=&quot;TIMESTAMP&quot; property=&quot;createTime&quot;/&gt;   &lt;/resultMap&gt;   &lt;select id=&quot;selectById&quot; resultMap=&quot;productsListMap&quot; parameterType=&quot;string&quot;&gt;       select       a.GUID,       a.VERSION,       a.REMARK,       a.UPDATE_TIME,       a.NAME,       b.GUID as file_GUID,       b.FILE_NAME,       b.FILE_ADDRESS,       b.CREATE_TIME       from demo_file_management a       left join demo_file_info b on a.GUID = b.INFO_ID       &lt;where&gt;           a.DELETE_FLG = &#x27;0&#x27;           &lt;if test=&quot;id != null and id != &#x27;&#x27;&quot;&gt;               and a.GUID = #&#123;id&#125;           &lt;/if&gt;       &lt;/where&gt;   &lt;/select&gt;
第二种方式（适用于分页查询）
采用两套查询，主查询和子查询进行配合（缺点就是，效率不如第一种，但是可以分页使用，不限制连表方式）。

&lt;resultMap id=&quot;productsListMap&quot; type=&quot;com.sgcc.demo.model.bo.DemoFileManagementBo&quot; extends=&quot;BaseResultMap&quot;&gt;      &lt;collection property=&quot;fileInfos&quot;  ofType=&quot;com.sgcc.demo.model.po.DemoFileInfo&quot;&gt;          &lt;id column=&quot;file_GUID&quot; jdbcType=&quot;VARCHAR&quot; property=&quot;guid&quot;/&gt;          &lt;result column=&quot;INFO_ID&quot; jdbcType=&quot;VARCHAR&quot; property=&quot;infoId&quot;/&gt;          &lt;result column=&quot;FILE_NAME&quot; jdbcType=&quot;VARCHAR&quot; property=&quot;fileName&quot;/&gt;          &lt;result column=&quot;FILE_ADDRESS&quot; jdbcType=&quot;VARCHAR&quot; property=&quot;fileAddress&quot;/&gt;          &lt;result column=&quot;CREATE_TIME&quot; jdbcType=&quot;TIMESTAMP&quot; property=&quot;createTime&quot;/&gt;      &lt;/collection&gt;  &lt;/resultMap&gt;  &lt;resultMap id=&quot;productsListMap1&quot; type=&quot;com.sgcc.demo.model.bo.DemoFileManagementBo&quot;&gt;      &lt;id column=&quot;GUID&quot; jdbcType=&quot;VARCHAR&quot; property=&quot;guid&quot;/&gt;      &lt;result column=&quot;NAME&quot; jdbcType=&quot;VARCHAR&quot; property=&quot;name&quot;/&gt;      &lt;result column=&quot;VERSION&quot; jdbcType=&quot;VARCHAR&quot; property=&quot;version&quot;/&gt;      &lt;result column=&quot;REMARK&quot; jdbcType=&quot;VARCHAR&quot; property=&quot;remark&quot;/&gt;      &lt;result column=&quot;UPDATE_TIME&quot; jdbcType=&quot;TIMESTAMP&quot; property=&quot;updateTime&quot;/&gt;      &lt;result column=&quot;DELETE_FLG&quot; jdbcType=&quot;CHAR&quot; property=&quot;deleteFlg&quot;/&gt;      &lt;collection property=&quot;fileInfos&quot; ofType=&quot;com.sgcc.demo.model.po.DemoFileInfo&quot; select=&quot;selectFileList&quot; column=&quot;GUID&quot;/&gt;  &lt;/resultMap&gt;  &lt;!--主查询--&gt;  &lt;select id=&quot;select&quot; resultMap=&quot;productsListMap1&quot; parameterType=&quot;com.sgcc.demo.model.po.DemoFileManagement&quot;&gt;      select      a.GUID,      a.VERSION,      a.REMARK,      a.UPDATE_TIME,      a.NAME      from demo_file_management a      &lt;where&gt;          a.DELETE_FLG = &#x27;0&#x27;          &lt;if test=&quot;name != null and name != &#x27;&#x27;&quot;&gt;              and a.NAME LIKE concat(&quot;%&quot;,#&#123;name&#125;,&quot;%&quot;)          &lt;/if&gt;      &lt;/where&gt;      Order by  a.UPDATE_TIME desc  &lt;/select&gt;  &lt;!--  子查询  --&gt;  &lt;select id=&quot;selectFileList&quot; resultType=&quot;com.sgcc.demo.model.po.DemoFileInfo&quot;&gt;      select          b.GUID as guid,          b.FILE_NAME as fileName,          b.FILE_ADDRESS as fileAddress,          b.CREATE_TIME as createTime      from          demo_file_info b      where          b.INFO_ID = #&#123;guid&#125;  &lt;/select&gt;

基础操作命令查看用户信息select user, host from mysql.user;

创建用户添加权限 ( 所有数据库用 * 代替 )grant all privileges on 数据库名.* to 账号@localhost identified by &#39;密码&#39;;
grant all privileges on 数据库名.* to 账号@&#39;%&#39; identified by &#39;密码&#39;;

刷新权限FLUSH PRIVILEGES;

修改密码update user set authentication_string=password(&#39;新密码&#39;) where user=&#39;root&#39; and Host=&#39;localhost&#39;;

删除用户DROP USER &#39;test&#39;@&#39;localhost&#39;;

显示修改超时等待时间show global variables like &#39;wait_timeout&#39;;
set global wait_timeout=600;

显示修改最大连接数SHOW VARIABLES LIKE &#39;%max_con%&#39;;
SET GLOBAL max_connections = 1000;

忽略大小写lower_case_table_names=1

解决group by问题sql_mode=&quot;IGNORE_SPACE,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION&quot;

mysql8之后操作#必须先创建用户(密码规则：mysql8.0以上密码策略限制必须要大小写加数字特殊符号)：
create user matt@&#39;%&#39; identified  by &#39;Matt1234.&#39;;
#再进行赋值
grant all privileges on *.* to matt@&#39;%&#39; with grant option;
flush privileges;
#mysql8使用的是caching_sha2_password加密规则，最简单的方法是修改远程连接用户的加密规则：
ALTER USER &#39;matt&#39;@&#39;%&#39; IDENTIFIED WITH mysql_native_password BY &#39;Matt1234.&#39;;

