创建docker-compose.ymlversion: &#x27;3&#x27;services:  nginx:    # 镜像名    image: nginx:1.19.8    # 容器名    container_name: matt-nginx    # 重启策略    restart: always    privileged: true        # 端口映射    ports:      - 80:80                      - 8080:8080    # 挂载目录     volumes:      - /home/docker-container/nginx/conf/nginx.conf:/etc/nginx/nginx.conf      - /home/docker-container/nginx/conf.d:/etc/nginx/conf.d      - /home/docker-container/nginx/html:/usr/share/nginx/html      - /home/docker-container/nginx/logs:/var/log/nginx    environment:        - TZ=Asia/Shanghai

启动
将需要代理的前端vue项目放入html文件夹中, 在conf.d文件夹中加入nginx配置文件,重启nginx即可

