nginx代理配置文件示例server &#123;    listen       8080;    server_name  127.0.0.1;    location / &#123;        #此处填写的地址是docker容器的html地址,因为我们已经做了挂载,例如宿主机/data/nginx/html/demo,则下面root应该填写/usr/share/nginx/html/demo        root  /usr/share/nginx/html/demo;        try_files $uri $uri/ /index.html;        index  index.html index.htm;    &#125;    location /api/&#123;		proxy_set_header Host $http_host;		proxy_set_header X-Real-IP $remote_addr;		proxy_set_header REMOTE-HOST $remote_addr;		proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;		proxy_pass http://172.19.20.129:8090/;    &#125; &#125;

JAVA文件以流的形式存在Mysql(blob)数据库,mysql最大支持4G文件(longblb)

直接将流转换为byte存入数据库public Response uploadBlob(MultipartFile file) &#123;    //数据库实体类 改成自己的    FileUpload fileUpload = new FileUpload();    fileUpload.setFileName(file.getOriginalFilename());    try &#123;        fileUpload.setContent(FileTypeUtils.input2byte(file.getInputStream()));    &#125; catch (IOException e) &#123;        e.printStackTrace();    &#125;    save(fileUpload);    return Response.ok(&quot;成功&quot;, fileUpload.getId());&#125;/** * 将 流 转换为byte * * @param inStream * @return * @throws IOException */public static byte[] input2byte(InputStream inStream) throws IOException &#123;    try (ByteArrayOutputStream swapStream = new ByteArrayOutputStream()) &#123;        byte[] buff = new byte[inStream.available()];        while (inStream.read(buff) != -1) &#123;            swapStream.write(buff);        &#125;        return swapStream.toByteArray();    &#125; catch (Exception e) &#123;        e.printStackTrace();    &#125;    return null;&#125;

下载文件输出文件流到前端public void getFile(String id, HttpServletRequest request, HttpServletResponse response) throws UnsupportedEncodingException &#123;       // 获取数据库文件信息       FileUpload fileUpload = getById(id);       if (fileUpload.getContent() != null) &#123;           //获取存储的文件名称           String filename = fileUpload.getFileName();           //获取浏览器版本           String userAgent = request.getHeader(&quot;USER-AGENT&quot;);           //IE浏览器           if (StringUtils.contains(userAgent, &quot;MSIE&quot;)) &#123;               filename = URLEncoder.encode(filename, &quot;UTF8&quot;);           &#125;           //google,火狐浏览器           else if (StringUtils.contains(userAgent, &quot;Mozilla&quot;)) &#123;               filename = new String(filename.getBytes(), &quot;ISO8859-1&quot;);           &#125;           //其他浏览器           else &#123;               filename = URLEncoder.encode(filename, &quot;UTF8&quot;);           &#125;           try &#123;               byte[] fileStream = fileUpload.getContent();               response.setHeader(&quot;content-type&quot;, &quot;application/octet-stream&quot;);               //这边可以设置文件下载时的名字，我这边用的是文件原本的名字，可以根据实际场景设置               response.setContentType(&quot;application/octet-stream&quot;);               response.setHeader(&quot;Content-Disposition&quot;, &quot;attachment;filename=&quot; + URLEncoder.encode(filename, &quot;UTF-8&quot;));               OutputStream toClient = new BufferedOutputStream(response.getOutputStream());               toClient.write(fileStream);               toClient.flush();               toClient.close();           &#125; catch (Exception e) &#123;               e.printStackTrace();           &#125;       &#125;   &#125;
流的方式前端要指定  responseType: ‘blob’methods: &#123;   downLoad() &#123;     if (this.fileId) &#123;       request(&#123;         url: &quot;localhost:8080/file/getFile&quot;,         method: &quot;get&quot;,         params: &#123; id: this.fileId &#125;,         //指定 responseType         responseType: &#x27;blob&#x27;       &#125;).then((resp) =&gt; &#123;         let blob = new Blob([resp],&#123;           type:&#x27;application/vnd.ms-excel&#x27;         &#125;);         let objectUrl = URL.createObjectURL(blob);  //生成一个url         this.downloadFile(objectUrl,this.form.fileName)       &#125;);     &#125;   &#125;&#125;


转成文件public File getFile(String id, HttpServletRequest request, HttpServletResponse response) &#123;      // 获取数据库文件信息      FileUpload fileUpload = getById(id);      if (fileUpload.getContent() != null) &#123;          File file = null;          try &#123;              file = new File(fileUpload.getFileName());              if (!file.exists()) &#123;                  file.createNewFile();              &#125;              OutputStream os = new FileOutputStream(file);              os.write(fileUpload.getContent());              os.close();          &#125; catch (Exception e) &#123;              e.printStackTrace();          &#125;          return file;      &#125;  &#125;

最近有一个项目需求, 甲方数据库是原库, 数据需要实时更新且数据量特别大未分表, 所以就打算拿到甲方的数据自建数据库分表, 但是需要数据同步,所以就选用了阿里巴巴的方案Canal; 工作原理：解析MySQL的binlog日志，提供增量数据, 主要用途是基于 MySQL 数据库增量日志解析，提供增量数据订阅和消费;


示例环境为Linux单机Canal环境, Windows环境大同小异;

Mysql配置查看mysql是否打开bin_log日志#查看mysql是否打开bin_log日志
show variables like &#39;%log_bin%&#39;;

如果未开启, 修改mysql的my.cnf配置, Windows修改my.ini文件, 如下:[mysqld]
log-bin=mysql-bin # 开启 binlog
binlog-format=ROW # 选择 ROW 模式
server_id=1 # 配置 MySQL replaction 需要定义，不要和 canal 的 slaveId 重复


授权 canal 连接 MySQL 帐号具备做为 MySQL slave 的权限, 若是已有帐户可直接 grant(省略第三步)CREATE USER canal IDENTIFIED BY &#39;canal&#39;; 
GRANT SELECT, REPLICATION SLAVE, REPLICATION CLIENT ON *.* TO &#39;canal&#39;@&#39;%&#39;;
-- GRANT ALL PRIVILEGES ON *.* TO &#39;canal&#39;@&#39;%&#39; ;
FLUSH PRIVILEGES;

